`timescale 1ns / 1ps

module async_filo_tb ();

  // Parameters
  localparam DATA_WIDTH = 8;
  localparam DEPTH = 8;

  // Testbench Signals
  reg w_clk;
  reg r_clk;
  reg w_rst;
  reg r_rst;
  reg push;
  reg pop;
  reg [DATA_WIDTH-1:0] w_data;
  wire [DATA_WIDTH-1:0] r_data;
  wire r_empty;
  wire w_full;

  // Local Flags and Counter
  integer counter;
  logic empty, full;
  reg [DATA_WIDTH-1:0] pushed_data[0:DEPTH-1];
  reg [DATA_WIDTH-1:0] rd_data;

  // Instantiate the DUT (Device Under Test)
  async_filo #(
      .DATA_WIDTH(DATA_WIDTH),
      .DEPTH(DEPTH)
  ) async_filo_inst (
      .w_clk(w_clk),
      .w_rst(w_rst),
      .push(push),
      .r_rst(r_rst),
      .r_clk(r_clk),
      .pop(pop),
      .w_data(w_data),
      .r_data(r_data),
      .r_empty(r_empty),
      .w_full(w_full)
  );

  initial begin
    w_clk = 0;
    forever #5 w_clk = ~w_clk;
  end

  initial begin
    r_clk = 0;
    forever #7 r_clk = ~r_clk;
  end

  initial begin

    counter = 0;
    empty = 1;
    full = 0;

    w_rst = 1;
    r_rst = 1;
    push = 0;
    pop = 0;
    w_data = 0;


    $display("Applying Reset...");
    #20;
    w_rst = 0;
    r_rst = 0;
    $display("Reset Complete");
    $display("Depth = 8");
    $display("Empty Status: %0d | Full Status: %0d", empty, full);

    simulate_filo_behavior();

    $display("-------------------------------");
    $display("Performing 3 Push Operations...");
    push_data($urandom_range(0, (1 << DATA_WIDTH) - 1));
    push_data($urandom_range(0, (1 << DATA_WIDTH) - 1));
    push_data($urandom_range(0, (1 << DATA_WIDTH) - 1));

    $display("Performing 3 Pop Operations...");
    pop_data();
    pop_data();
    pop_data();

    // End Simulation
    $display("Test Completed.");
    #100;
    $finish;
  end

  task simulate_filo_behavior;
    begin
      $display("Simulating FILO Behavior - Push Operations...");
      for (int i = 0; i < DEPTH; i++) begin
        if (!full) begin
          push_data($urandom_range(0, (1 << DATA_WIDTH) - 1));
        end
      end

      $display("Simulating FILO Behavior - Pop Operations...");
      for (int i = 0; i < DEPTH; i++) begin
        if (!empty) begin
          pop_data();
        end
      end
    end
  endtask

  task push_data(input [DATA_WIDTH-1:0] data_in);
    begin
      if (!full) begin
        push = 1;
        w_data = data_in;
        pushed_data[counter] = data_in;
        @(posedge w_clk);
        push    = 0;
        counter = counter + 1;
        full    = (counter == DEPTH);
        empty   = 0;

        $display("Pushed Data: %h | Counter: %0d | Full: %0d | Empty: %0d ", data_in, counter,
                 full, empty);
      end else begin
        $display("Cannot Push, FILO is Full.");
      end
    end
  endtask

  task pop_data;
    reg [DATA_WIDTH-1:0] expected_data;
    begin
      if (!empty) begin
        rd_data = pushed_data[counter-1];
        pop = 1;
        full    = 0;
        @(posedge r_clk);
        pop = 0;

        $display("Popped Data: %h | Counter: %0d | Full: %0d | Empty: %0d", rd_data, counter - 1,
                 full, (counter == 1));

        counter = counter - 1;

      end else begin
        $display("Cannot Pop, FILO is Empty.");
      end
    end
  endtask

endmodule

output.rtl/async_filo.sv:
Module declaration
module async_filo (
    // Inputs
    input clock [DATA_WIDTH-1:0] w_data,
    input clock [DATA_WIDTH-1:0] r_data,
    input clock w_clk,
    input clock r_clk,
    input high [1] w_rst,
    input high [1] r_rst,
    // Outputs
    output high [1] w_full,
    output high [1] r_empty
);

// Module parameters
parameter DATA_WIDTH = 8;
parameter DEPTH = 8;

// Module internals
reg [DEPTH][DATA_WIDTH] mem;
reg [DATA_WIDTH-1:0] w_ptr, r_ptr, w_count_bin, r_count_bin;
always @posedge w_clk begin
    // Convert binary write count to Gray code
    w_ptr = bin2gray(w_count_bin);
    w_count_bin = w_count_bin + 1;
end
always @posedge r_clk begin
    // Convert binary read count to Gray code
    r_ptr = bin2gray(r_count_bin);
    r_count_bin = r_count_bin + 1;
end

// Function to convert binary to Gray code
function bit [DATA_WIDTH-1:0] bin2gray(bit [DATA_WIDTH-1:0] bin_in);
    out = bin_in ^ (bin_in >> 1);
endfunction

// Function to convert Gray code to binary
function bit [DATA_WIDTH-1:0] gray2bin(bit [DATA_WIDTH-1:0] gray_in);
    out = gray_in ^ (gray_in >> 1);
endfunction

// Generate w_full and r_empty signals
wire w_full = (w_ptr >= r_ptr) ? 1 : 0;
wire r_empty = (r_ptr <= w_ptr) ? 1 : 0;

// Event-driven process for push and pop operations
process (*) begin
    while (!w_rst && !r_rst) begin
        // Simulate push operation
        if (!w_full) begin
            w_data is written to mem[w_ptr]
            w_ptr is incremented
        end

        // Simulate pop operation
        if (!r_empty) begin
            r_data is read from mem[r_ptr]
            r_ptr is decremented
        end
    end
endprocess

endmodule

