        m_axis_tready_1 = 0; 
        s_axis_tdata = 8'h5A;


        @(negedge clk);
        m_axis_tready_1 = 1; 
        s_axis_tdata = 8'h5b;

        @(negedge clk);
        s_axis_tvalid = 0;

        @(negedge clk);

        // Change ready signals
        m_axis_tready_1 = 0;
        m_axis_tready_2 = 1;
        m_axis_tready_3 = 1;

        #10 s_axis_tvalid = 1;
        s_axis_tdata = 8'hF0;

        #10;

        $finish;
    end

