`timescale 1ns/1ps

module tb_pseudoRandGenerator_ca;


  logic         clock;
  logic         reset;
  logic [15:0]  CA_seed;
  logic [1:0]   rule_sel;  
  logic [15:0]  CA_out;

  pseudoRandGenerator_ca dut (
    .clock(clock),
    .reset(reset),
    .CA_seed(CA_seed),
    .rule_sel(rule_sel),
    .CA_out(CA_out)
  );

  initial begin
    clock = 0;
    forever #5 clock = ~clock;
  end

  initial begin
    reset    = 1;
    CA_seed  = 16'h1;    
    rule_sel = 2'b10;    
    #12;                
    reset = 0;
  end

  int cycle_count;
  int first_seen[0:65535];

  initial begin
    int j;
    for (j = 0; j < 65536; j++) begin
      first_seen[j] = -1;
    end
  end

  initial begin
    int i;
    @(negedge reset);
    @(posedge clock);
    cycle_count = 0;
    for (i = 0; i < 65536; i++) begin
      @(posedge clock);
      cycle_count++;
      if (first_seen[CA_out] == -1) begin
        first_seen[CA_out] = cycle_count;
      end else begin
        $display("Cycle %0d: Value %h repeated; first seen at cycle %0d", 
                 cycle_count, CA_out, first_seen[CA_out]);
      end
    end
    $display("Completed 65,536 cycles. Simulation finished.");
    $finish;

  end

endmodule

output.rtl/pseudoRandGenerator_ca.sv:
module pseudo_rand_generator_ca(
    input logic clock,
    input logic reset,
    input logic[15:0] CA_seed,
    input logic[1:0] rule_sel,
    output logic[15:0] CA_out
);

    // Function to get previous bit value considering wrap-around
    function logic get_left_neighbor(bit pos) {
        if (pos == 0) return 15;
        else return pos - 1;
    }

    function logic get_right_neighbor(bit pos) {
        if (pos == 15) return 0;
        else return pos + 1;
    }

    // Compute next bit value based on rule
    function logic compute_next_bit(bit pos, logic[2:0] rule) {
        bit left = get_left_neighbor(pos);
        bit center = (CA_out[pos] ? 1 : 0);
        bit right = get_right_neighbor(pos);

        logic[3:0] triplet;
        triplet[2] = left;
        triplet[1] = center;
        triplet[0] = right;

        case (triplet)
            3'b111: out = 0;
            3'b110: out = 0;
            3'b101: out = 0;
            3'b100: out = 1;
            3'b011: out = 1;
            3'b010: out = 1;
            3'b001: out = 1;
            default: out = 0;
        endcase
    }

    // Always combinatorial block to compute next state
    always_comb begin
        logic[16:0] next_state = {15{0}};

        for (int i = 0; i < 16; i++) {
            next_state[i] = compute_next_bit(i, (rule_sel << 1) & 2);
        }
    end

    // Register to hold current state
    reg [15:0] CA_out;

    // State update
    always logic [
        posedge clock
    ] begin
        if (reset) begin
            CA_out = CA_seed;
        else
            CA_out = next_state;
        end
    end

endmodule

output.rtl/cic_decimator.sv:
Module Implementation
module rtl::cic_decimator (
    input_tdata_t input_tdata,
    input_tvalid_t input_tvalid,
    input_tready_t input_tready,
    output_tdata_t output_tdata,
    output_tvalid_t output_tvalid,
    output_tready_t output_tready,
    clock_tclk,
    rst_trst
);

// Internal variables
reg [WIDTH-1:0] cycle_reg;
reg [REG_WIDTH-1:0] acc_integrator;
reg [REG_WIDTH-1:0] acc_comb;
reg [M-1:0] delay_reg;

// Parameters
parameter WIDTH = 16;
parameter RMAX = 2;
parameter M = 1;
parameter N = 2;
parameter REG_WIDTH = WIDTH + ($clog2(RMAX) + $clog2(M) * N);

// Integrator Section
generate for (k = 0 to N-1)
    integer k_integ = k;
    always @(posedge clock_tclk)
        if (input_tvalid && input_tready)
            acc_integrator = acc_integrator + ((input_tdata >> WIDTH) + 1);
endgenerate

// Comb Section
generate for (k = 0 to N-1)
    integer k_comb = k;
    always @(posedge clock_tclk)
        if (output_tvalid && output_tready)
            acc_comb = acc_comb - (acc_comb >> M) - (delay_reg[M-1]);
            // Update delay registers
            delay_reg = (delay_reg << 1) | (acc_comb >> (REG_WIDTH - M));
    else
        delay_reg = { {M-1}{0} };
endgenerate

// Decimation Control
always @(posedge clock_tclk)
    if (rst_trst) 
        cycle_reg = 0;
    else 
        if (!input_tvalid || !input_tready)
            cycle_reg = 0;
        else 
            cycle_reg = cycle_reg + 1;
            if (cycle_reg >= (RMAX - 1))
                cycle_reg = 0;
        end
    end

// Output Generation
always @(posedge clock_tclk)
    if (input_tvalid && input_tready && cycle_reg == 0)
        output_tdata = acc_comb >> (WIDTH) & ((1 << WIDTH) - 1);
        output_tvalid = 1;
    end

