module event_scheduler_tb;


    reg clk;
    reg reset;
    reg add_event;
    reg cancel_event;
    reg [3:0] event_id;
    reg [15:0] timestamp;
    reg [3:0] priority_in;
    reg [3:0] trig_id;
    reg [15:0] trig_time;
    reg [15:0] future_time;
    wire event_triggered;
    wire [3:0] triggered_event_id;
    wire error;
    wire [15:0] current_time;


    event_scheduler dut (
        .clk(clk),
        .reset(reset),
        .add_event(add_event),
        .cancel_event(cancel_event),
        .event_id(event_id),
        .timestamp(timestamp),
        .priority_in(priority_in),
        .event_triggered(event_triggered),
        .triggered_event_id(triggered_event_id),
        .error(error),
        .current_time(current_time)
    );


    initial begin
        clk = 0;
        forever #5 clk = ~clk;
    end


    task wait_clock;
        @(posedge clk);
    endtask


    task wait_for_trigger(output [3:0] trig_id, output [15:0] trig_time);
        begin

            while (event_triggered !== 1) begin
                wait_clock;
            end
            trig_id = triggered_event_id;
            trig_time = current_time;

            wait_clock;
        end
    endtask

    initial begin

        reset = 1;
        add_event = 0;
        cancel_event = 0;
        event_id = 0;
        timestamp = 0;
        priority_in = 0;


        repeat (2) wait_clock;
        reset = 0;

        wait_clock;
        add_event = 1;
        event_id = 4;
        timestamp = 16'd20;
        priority_in = 4'd2;
