`timescale 1ns / 1ps
module fixed_priority_arbiter(
    input clk,                      // Clock signal
    input reset,                    // Active high reset signal
    input [7:0] req,                // 8-bit request signal; each bit represents a request from a different source
    input [7:0] priority_override,  // External priority override signal

    output reg [7:0] grant,         // 8-bit grant signal; only one bit will be set high based on priority
    output reg valid,               // Indicates if a request is granted
    output reg [2:0] grant_index    // Outputs the granted request index in binary format
); 

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            grant <= 8'b00000000;
            valid <= 1'b0;
            grant_index <= 3'b000;
        end 
        else begin
            if (priority_override != 8'b00000000) begin
                grant <= priority_override; 
                valid <= 1'b1;
                grant_index <= (priority_override[0] ? 3'd0 :
                                priority_override[1] ? 3'd1 :
                                priority_override[2] ? 3'd2 :
                                priority_override[3] ? 3'd3 :
                                priority_override[4] ? 3'd4 :
                                priority_override[5] ? 3'd5 :
                                priority_override[6] ? 3'd6 :
                                priority_override[7] ? 3'd7 : 3'd0);
            end
            else if (req[0]) begin
                grant <= 8'b00000001;
                grant_index <= 3'd0;
                valid <= 1'b1;
            end 
            else if (req[1]) begin
                grant <= 8'b00000010;
                grant_index <= 3'd1;
                valid <= 1'b1;
            end 
            else if (req[2]) begin
                grant <= 8'b00000100;
                grant_index <= 3'd2;
                valid <= 1'b1;
            end 
            else if (req[3]) begin
                grant <= 8'b00001000;
                grant_index <= 3'd3;
                valid <= 1'b1;
            end 
            else if (req[4]) begin
                grant <= 8'b00010000;
                grant_index <= 3'd4;
                valid <= 1'b1;
            end 
            else if (req[5]) begin
                grant <= 8'b00100000;
                grant_index <= 3'd5;
                valid <= 1'b1;
            end 
            else if (req[6]) begin
                grant <= 8'b01000000;
                grant_index <= 3'd6;
                valid <= 1'b1;
            end 
            else if (req[7]) begin
                grant <= 8'b10000000;
                grant_index <= 3'd7;
                valid <= 1'b1;
            end 
            else begin
                grant <= 8'b00000000;
                grant_index <= 3'd0;
                valid <= 1'b0;
            end
        end
    end
endmodule

input.rtl/gcd_controlpath_3.sv:
module gcd_controlpath_3 (
   input                    clk,
   input                    rst,
   input                    go,
   input                    equal,
   output logic [1:0]       controlpath_state,
   output logic             done
);
   localparam S0 = 2'd0;
   localparam S1 = 2'd1;
   localparam S2 = 2'd2;

   logic [1:0] curr_state, next_state;

   always_comb begin
      next_state = curr_state;
      case (curr_state)
         S0: begin
            if (!go)
               next_state = S0;
            else
               next_state = S2;
         end
         S1: begin
            next_state = S0;
         end
         S2: begin
            if (equal)
               next_state = S1;
            else
               next_state = S2;
         end
         default: begin
            next_state = S0;
         end
      endcase
   end

   always_ff @(posedge clk) begin
      if (rst)
         curr_state <= S0;
      else
         curr_state <= next_state;
   end

   always_ff @(posedge clk) begin
      if (rst)
         done <= 1'b0;
      else
         done <= (curr_state == S1);
   end

   assign controlpath_state = curr_state;

endmodule

input.rtl/gcd_controlpath_4.sv:
module gcd_controlpath_4 (
   input                    clk,
   input                    rst,
   input                    go,
   input                    equal,
   input                    greater_than,
   output logic [1:0]       controlpath_state,
   output logic             done
);


   logic [1:0] curr_state;
   logic [1:0] next_state;

   localparam S0 = 2'd0;
   localparam S1 = 2'd1;
   localparam S2 = 2'd2;
   localparam S3 = 2'd3;

   always_ff @ (posedge clk) begin
      if (rst) begin
         curr_state   <= S0;
      end else begin
         curr_state   <= next_state;
      end
   end

   always_comb begin
      case(curr_state)
         S0: begin
             if(!go)
                next_state = S0;
             else if (equal)
                next_state = S1;
             else if (greater_than)
                next_state = S2;
             else
                next_state = S3;
         end
         S1: begin
             next_state = S0;
         end
         S2: begin
             if(equal)
                next_state = S1;
             else if (greater_than)
                next_state = S2;
             else
                next_state = S3;
         end
         S3: begin
             if (equal)
                next_state = S1;
             else if (greater_than)
                next_state = S2;
             else
                next_state = S3;
         end
         default: begin
             next_state = S0;
         end
      endcase
   end

   always_ff @ (posedge clk) begin
     if(rst) begin
        done <= 1'b0;
     end else begin
        done <= (curr_state == S1);
     end
   end

   assign controlpath_state = curr_state;

endmodule

input.rtl/gcd_datapath_5.sv:
module gcd_datapath_5  #(
   parameter WIDTH = 4
   )(
   input                     clk,
   input                     rst,
   input  [WIDTH-1:0]        A,
   input  [WIDTH-1:0]        B,
   input  [1:0]              controlpath_state,
   output logic              equal,
   output logic              greater_than,
   output logic  [WIDTH-1:0] OUT
);

   logic [WIDTH-1:0] A_ff;
   logic [WIDTH-1:0] B_ff;

   localparam S0 = 2'd0;
   localparam S1 = 2'd1;
   localparam S2 = 2'd2;
   localparam S3 = 2'd3;

   always_ff @ (posedge clk) begin
      if (rst) begin
         A_ff <= 'b0;
         B_ff <= 'b0;
         OUT  <= 'b0;
      end else begin
         case (controlpath_state)
            S0: begin
                A_ff <= A;
                B_ff <= B;
             end
            S1: begin
                OUT  <= A_ff;
             end
            S2: begin
                if (greater_than)
                   A_ff <= A_ff - B_ff;
             end
            S3: begin
                if (!equal & !greater_than)
                   B_ff <= B_ff - A_ff;
             end
            default: begin
                A_ff <= 'b0;
                B_ff <= 'b0;
                OUT <= 'b0;
            end
         endcase
      end
   end

   always_comb begin
      case(controlpath_state)
         S0: begin
            equal        = (A == B)? 1'b1 : 1'b0;
            greater_than = (A >  B)? 1'b1 : 1'b0;
          end
          default: begin
            equal        = (A_ff == B_ff)? 1'b1 : 1'b0;
            greater_than = (A_ff >  B_ff)? 1'b1 : 1'b0;
          end
      endcase
   end
endmodule

input.rtl/gcd_datapath_6.sv:
module gcd_datapath_6  #(
   parameter WIDTH = 4
)(
   input                     clk,
   input                     rst,
   input      [WIDTH-1:0]    A,
   input      [WIDTH-1:0]    B,
   input      [1:0]          controlpath_state,
   output logic              equal,
   output logic [WIDTH-1:0]  OUT
);
   logic [WIDTH-1:0] A_ff, B_ff, OUT_ff;
   logic [$clog2(WIDTH+1):0] k_ff;

   logic [WIDTH-1:0] next_A_ff, next_B_ff, next_OUT;
   logic [$clog2(WIDTH+1):0] next_k_ff;

   logic [WIDTH-1:0] diff;
   logic [WIDTH-1:0] gcd_val;
   logic both_even, a_even, b_even;

   localparam S0 = 2'd0;
   localparam S1 = 2'd1;
   localparam S2 = 2'd2;

   always_comb begin
      next_A_ff = A_ff;
      next_B_ff = B_ff;
      next_k_ff = k_ff;
      next_OUT  = OUT_ff;
      gcd_val   = OUT_ff;
      diff      = 'b0;

      a_even    = (A_ff[0] == 1'b0);
      b_even    = (B_ff[0] == 1'b0);
      both_even = a_even && b_even;
      equal     = (A_ff == B_ff);

      case (controlpath_state)
         S0: begin
            next_A_ff = A;
            next_B_ff = B;
            next_k_ff = 'b0;
            next_OUT  = 'b0;
         end

         S1: begin
            if (A_ff == 0 && B_ff == 0) begin
               gcd_val = 0;
            end else if (A_ff == 0) begin
               gcd_val = (B_ff << k_ff);
            end else begin
               gcd_val = (A_ff << k_ff);
            end
            next_OUT = gcd_val;
         end

         S2: begin
            if ((A_ff != 0) && (B_ff != 0)) begin
               if (both_even) begin
                  next_A_ff = A_ff >> 1;
                  next_B_ff = B_ff >> 1;
                  next_k_ff = k_ff + 1;
               end else if (a_even && !b_even) begin
                  next_A_ff = A_ff >> 1;
               end else if (b_even && !a_even) begin
                  next_B_ff = B_ff >> 1;
               end else begin
                  if (A_ff >= B_ff) begin
                     diff = A_ff - B_ff;
                     next_A_ff = diff >> 1;
                     next_B_ff = B_ff;
                  end else begin
                     diff = B_ff - A_ff;
                     next_B_ff = diff >> 1;
                     next_A_ff = A_ff;
                  end
               end
            end else if (A_ff == 0 && B_ff != 0) begin
               next_A_ff = B_ff;
               next_B_ff = B_ff;
            end else if (B_ff == 0 && A_ff != 0) begin
               next_B_ff = A_ff;
               next_A_ff = A_ff;
            end
         end

         default: begin
            next_A_ff = 'b0;
            next_B_ff = 'b0;
            next_k_ff = 'b0;
            next_OUT  = 'b0;
         end
      endcase
   end

   always_ff @(posedge clk) begin
      if (rst) begin
         A_ff  <= 'b0;
         B_ff  <= 'b0;
         k_ff  <= 'b0;
         OUT_ff <= 'b0;
      end else begin
         A_ff  <= next_A_ff;
         B_ff  <= next_B_ff;
         k_ff  <= next_k_ff;
         OUT_ff <= next_OUT;
      end
   end

   assign OUT = OUT_ff;

endmodule

input.rtl/modular_exponentiation.sv:
`timescale 1ns/1ps
//-----------------------------------------------------------------------------
// modular_exponentiation module: Computes (base^exponent) mod mod_val using the
// square-and-multiply algorithm.
// This module reuses the modular_multiplier module for multiplication operations.
//-----------------------------------------------------------------------------
module modular_exponentiation #(
    parameter WIDTH = 8
)(
    input                     clk,
    input                     rst,
    input                     start,
    input      [WIDTH-1:0]    base,
    input      [WIDTH-1:0]    exponent,
    input      [WIDTH-1:0]    mod_val,
    output reg [WIDTH-1:0]    result,
    output reg                done
);
    // FSM state definitions.
    localparam STATE_IDLE        = 0;
    localparam STATE_INIT        = 1;
    localparam STATE_CHECK       = 2;
    localparam STATE_WAIT_RESULT = 3;
    localparam STATE_MULT_BASE   = 4;
    localparam STATE_WAIT_BASE   = 5;
    localparam STATE_SHIFT       = 6;
    localparam STATE_DONE        = 7;

    reg [3:0]       state;
    reg [WIDTH-1:0] res_reg;
    reg [WIDTH-1:0] base_reg;
    reg [WIDTH-1:0] exp_reg;

    // Signals for the modular multiplier instance.
    reg mult_start;
    reg [WIDTH-1:0] mult_A, mult_B, mult_mod;
    wire [WIDTH-1:0] mult_result;
    wire mult_done;

    // Instantiate the modular_multiplier.
    modular_multiplier #(
        .WIDTH(WIDTH)
    ) mod_mult_inst (
        .clk(clk),
        .rst(rst),
        .start(mult_start),
        .A(mult_A),
        .B(mult_B),
        .mod_val(mult_mod),
        .result(mult_result),
        .done(mult_done)
    );

    always @(posedge clk) begin
        if(rst) begin
            state      <= STATE_IDLE;
            res_reg    <= 0;
            base_reg   <= 0;
            exp_reg    <= 0;
            result     <= 0;
            done       <= 0;
            mult_start <= 0;
        end else begin
            case(state)
                STATE_IDLE: begin
                    done <= 0;
                    if(start)
                        state <= STATE_INIT;
                end
                STATE_INIT: begin
                    res_reg  <= 1;                // Initialize result to 1.
                    base_reg <= base % mod_val;    // Reduce base modulo mod_val.
                    exp_reg  <= exponent;
                    state    <= STATE_CHECK;
                end
                STATE_CHECK: begin
                    if(exp_reg == 0) begin
                        if(base_reg == 0 & mod_val==1)
                            result <= 0;
                        else
                            result <= res_reg;
                        state  <= STATE_DONE;
                    end else begin
                        if(exp_reg[0] == 1'b1) begin
                            mult_A   <= base_reg;
                            mult_B   <= base_reg;
                            mult_mod <= mod_val;
                            mult_start <= 1;
                            state <= STATE_WAIT_RESULT;
                        end else begin
                            state <= STATE_MULT_BASE;
                        end
                    end
                end
                STATE_WAIT_RESULT: begin
                    mult_start <= 0;
                    if(mult_done) begin
                        res_reg <= mult_result;
                        state <= STATE_MULT_BASE;
                    end
                end
                STATE_MULT_BASE: begin
                    mult_A   <= base_reg;
                    mult_B   <= res_reg;
                    mult_mod <= mod_val;
                    mult_start <= 1;
                    state <= STATE_WAIT_BASE;
                end
                STATE_WAIT_BASE: begin
                    mult_start <= 0;
                    if(mult_done) begin
                        base_reg <= mult_result;
                        state <= STATE_SHIFT;
                    end
                end
                STATE_SHIFT: begin
                    exp_reg <= exp_reg >> 1; // Shift exponent right.
                    state   <= STATE_CHECK;
                end
                STATE_DONE: begin
                    done <= 1;
                    // Remain in DONE state until start is deasserted.
                    if(!start)
                        state <= STATE_IDLE;
                end
                default: state <= STATE_IDLE;
            endcase
        end
    end
endmodule

input.rtl/modular_multiplier.sv:
`timescale 1ns/1ps
//-----------------------------------------------------------------------------
// modular_multiplier module: Computes (A * B) mod mod_val
// Implements a sequential shift‐and‐add multiplication followed by a
// single modulo operation at the end.
//-----------------------------------------------------------------------------
module modular_multiplier #(
    parameter WIDTH = 8
)(
    input                     clk,
    input                     rst,
    input                     start,
    input      [WIDTH-1:0]    A,
    input      [WIDTH-1:0]    B,
    input      [WIDTH-1:0]    mod_val,
    output reg [WIDTH-1:0]    result,
    output reg                done
);
    // a_reg now stores A extended to 2*WIDTH bits to accommodate shifts.
    reg [2*WIDTH-1:0] a_reg;
    reg [WIDTH-1:0]   b_reg;
    reg [2*WIDTH-1:0] prod;   // Accumulates the full product
    reg [($clog2(WIDTH+1))-1:0] count;  // Iteration counter for WIDTH bits
    reg busy;

    always @(posedge clk) begin
        if(rst) begin
            result  <= 0;
            prod    <= 0;
            a_reg   <= 0;
            b_reg   <= 0;
            count   <= 0;
            busy    <= 0;
            done    <= 0;
        end else begin
            if(start && !busy) begin
                busy    <= 1;
                // Initialize registers.
                // Extend A to 2*WIDTH bits.
                a_reg   <= { {WIDTH{1'b0}}, A };
                b_reg   <= B;
                prod    <= 0;
                count   <= WIDTH;
                done    <= 0;
            end else if(busy) begin
                if(count > 0) begin
                    // If the current LSB of b_reg is 1, add a_reg to the product.
                    if(b_reg[0] == 1'b1)
                        prod <= prod + a_reg;
                    // Shift a_reg left to align with the next bit.
                    a_reg <= a_reg << 1;
                    // Shift b_reg right to process the next bit.
                    b_reg <= b_reg >> 1;
                    count <= count - 1;
                end else begin
                    // Once multiplication is done, perform the modulo operation.
                    result <= prod % mod_val;
                    done   <= 1;
                    busy   <= 0;
                end
            end else begin
                done <= 0;
            end
        end
    end
endmodule

