module tb_multiplexer;

  reg clk;
  reg rst_n;
  reg [8*3-1:0] inp;
  reg [1:0] sel;
  reg bypass;
  wire [7:0] out;
  integer i, j;
  reg [7:0] expected;

  multiplexer #(
      .DATA_WIDTH(8),
      .NUM_INPUTS(3),
      .REGISTER_OUTPUT(1),
      .HAS_DEFAULT(1),
      .DEFAULT_VALUE(8'h55)
  ) dut (
      .clk(clk),
      .rst_n(rst_n),
      .inp(inp),
      .sel(sel),
      .bypass(bypass),
      .out(out)
  );

  always #5 clk = ~clk;

  initial begin
    clk = 0; rst_n = 0; inp = 0; sel = 0; bypass = 0;
    repeat(2) @(posedge clk);
    rst_n = 1;
    repeat(2) @(posedge clk);
    for (i = 0; i < 10; i = i + 1) begin
      inp = {($random() & 8'hFF), ($random() & 8'hFF), ($random() & 8'hFF)};
      for (j = 0; j < 4; j = j + 1) begin
        sel = j[1:0];
        bypass = 0;
        #1;
        if (sel < 3) expected = inp[sel*8 +: 8];
        else         expected = 8'h55;
        @(posedge clk);
        @(posedge clk);
        if (out !== expected)
          $display("Time=%0t Sel=%0d Bypass=%0b Inp=%0h Expected=%0h Got=%0h", $time, sel, bypass, inp, expected, out);
        else
          $display("Time=%0t PASSED Sel=%0d Bypass=%0b", $time, sel, bypass);

        bypass = 1;
        #1;
        expected = inp[0 +: 8];
        @(posedge clk);
        @(posedge clk);
        if (out !== expected)
          $display("Time=%0t Sel=%0d Bypass=%0b Inp=%0h Expected=%0h Got=%0h", $time, sel, bypass, inp, expected, out);
        else
          $display("Time=%0t PASSED Sel=%0d Bypass=%0b", $time, sel, bypass);
      end
    end
    $finish;
  end

endmodule

output.rtl/multiplexer.sv:
module multiplexer #( 
    parameter DATA_WIDTH = 8,
    parameter NUM_INPUTS = 4,
    parameter REGISTER_OUTPUT = 0,
    parameter HAS_DEFAULT = 0,
    parameter [DATA_WIDTH-1:0] DEFAULT_VALUE = {DATA_WIDTH{1'b0}}
)(
    input  wire [((NUM_INPUTS * DATA_WIDTH)+NUM_INPUTS-1):0] inp,
    input  wire [$clog2(NUM_INPUTS)-1:0]       sel,
    input  wire [1:0]                         bypass,
    input  wire [1:0]                         rst_n,
    input  wire [((NUM_INPUTS * DATA_WIDTH)-1):0] sel_vec,
    output reg [DATA_WIDTH-1:0]             out
);

    // Construct input array
    wire [((NUM_INPUTS * DATA_WIDTH)-1):0] inp_array;
    generate
        local param i = 0;
        do until(i == ((NUM_INPUTS * DATA_WIDTH)-1))
            inp_array[i] = inp[(i / DATA_WIDTH)][i % DATA_WIDTH];
            i = i + 1;
        end
    endgenerate

    // Selection logic
    if (HAS_DEFAULT == 1 && sel > (log2(NUM_INPUTS) - 1)) begin
        out = DEFAULT_VALUE;
    elsif (bypass == 1) begin
        out = inp_array[0];
    else begin
        out = inp_array[sel];
    end
endmodule

