`timescale 1ns / 1ps

module nmea_decoder_tb;

    reg clk;
    reg reset;
    reg [7:0] serial_in;
    reg serial_valid;
    reg watchdog_timeout_en;

    wire [15:0] data_out;
    wire data_valid;
    wire error_overflow;
    wire valid_sentence;
    wire watchdog_timeout;
    wire [15:0] data_out_bin;
    wire data_bin_valid;

    reg [7:0] sentence [0:79];
    integer i;

    nmea_decoder dut (
        .clk(clk),
        .reset(reset),
        .serial_in(serial_in),
        .serial_valid(serial_valid),
        .watchdog_timeout_en(watchdog_timeout_en),
        .data_out(data_out),
        .data_valid(data_valid),
        .data_out_bin(data_out_bin),
        .data_bin_valid(data_bin_valid),
        .error_overflow(error_overflow),
        .valid_sentence(valid_sentence),
        .watchdog_timeout(watchdog_timeout)
    );

    initial begin
        clk = 0;
        forever #5 clk = ~clk;
    end

    task send_char(input [7:0] char);
        begin
            serial_in = char;
            serial_valid = 1;
            #5;
            serial_valid = 0;
            #5;
        end
    endtask

