// Module declaration
module control_fsm(
    // Inputs
    input wire [7:0] i_clk,
    input wire [1:0] i_rst_async_n,
    input wire i_enable,
    input wire i_subsampling,
    input wire i_iw,
    input wire i_calc_valid,
    input wire i_calc_fail,
    input wire i_wd,
    input wire i_vth,

    // Outputs
    output reg [7:0] o_start_calc,
    output reg [7:0] o_valid,
    output reg [7:0] o_subsampling,
    output reg [7:0] o_wd,
    output reg [7:0] o_vth);

// FSM state variable
reg fsm_state = 0;

// Variables
parameter NBW_WAIT = 32;
reg gen_counter_val = 0;
reg wait_counter_val = 0;

always @posedge i_clk begin
    // State transitions
    case(fsm_state)
        0: // PROC_CONTROL_CAPTURE_ST
            if(i_enable)
                fsm_state = 1;
        1: // PROC_DATA_CAPTURE_ST
            if(gen_counter_val == 0)
                fsm_state = 2;
            else
                fsm_state = 1;
        2: // PROC_CALC_START_ST
            gen_counter_val = 0;
            wait_counter_val = $signed(i_wait);
            fsm_state = 3;
        3: // PROC_CALC_ST
            if($clock && !i_enable)
                fsm_state = 4;
            else if($clock && i_enable)
                fsm_state = 3;
        4: // PROC_WAIT_ST
            if(wait_counter_val == 0 || !i_enable)
                fsm_state = 0;
    endcase
end

// General Purpose Counter
wire [7:0] gen_counter;

always @negedge i_rst_async_n + '@posedge i_clk begin
    gen_counter = $signed(NBW_WAIT);
end

// Timeout Counter
wire [7:0] wait_counter;

always @posedge i_clk begin
    wait_counter = $signed(i_wait);
    gen_counter = 0;
end

// Output Calculation
always begin
    o_start_calc = fsm_state == 3;

    // o_valid
    o_valid = (
        (fsm_state >= 1 && fsm_state <= 3) && 
        iEnable && 
        ($signed(gen_counter) > 0)) ||
        (fsm_state == 0 && iEnable && $signed(gen_counter));

    // o_subsampling
    o_subsampling = i_subsampling;

    // o_wd
    o_wd = i_wd;

    // o_vth
    o_vth = i_vth;
end

input.rtl/adder_tree.sv:
module adder_tree #(
  parameter NUM_INPUTS = 8,
  parameter DATA_WIDTH = 32
)
(
  input  logic                                     clk,
  input  logic                                     arst_n,
  input  logic                                     valid_in,
  input  logic [DATA_WIDTH-1:0]                    data_in [NUM_INPUTS],
  output logic [DATA_WIDTH+$clog2(NUM_INPUTS)-1:0] sum_out,
  output logic                                     valid_out
);

  // Calculate the number of pipeline stages:
  localparam NUM_STAGES = $clog2(NUM_INPUTS);

  // Pipeline registers for data and valid signals.
  logic [DATA_WIDTH+$clog2(NUM_INPUTS)-1:0] stage_reg [0:NUM_STAGES][0:NUM_INPUTS-1];
  logic valid_stage [0:NUM_STAGES];
  integer i, s, j;

  // Stage 0: Register the input data.
  always_ff @(posedge clk or negedge arst_n) begin
    if (!arst_n) begin
      for (i = 0; i < NUM_INPUTS; i = i + 1)
        stage_reg[0][i] <= '0;
      valid_stage[0] <= 1'b0;
    end
    else if (valid_in) begin
      for (i = 0; i < NUM_INPUTS; i = i + 1)
        // Sign extend if needed.
        stage_reg[0][i] <= {{($clog2(NUM_INPUTS)){data_in[i][DATA_WIDTH-1]}}, data_in[i]};
      valid_stage[0] <= 1'b1;
    end 
    else begin
      valid_stage[0] <= 1'b0;
    end
  end

  // Subsequent stages: each stage halves the number of values.
  generate
    for (genvar s = 1; s <= NUM_STAGES; s = s + 1) begin : stage_pipeline
      localparam int NUM_ELEMS = NUM_INPUTS >> s;
      always_ff @(posedge clk or negedge arst_n) begin
        if (!arst_n) begin
          for (j = 0; j < NUM_ELEMS; j = j + 1)
            stage_reg[s][j] <= '0;
          valid_stage[s] <= 1'b0;
        end
        else if (valid_stage[s-1]) begin
          for (j = 0; j < NUM_ELEMS; j = j + 1)
            stage_reg[s][j] <= stage_reg[s-1][2*j] + stage_reg[s-1][2*j+1];
          valid_stage[s] <= 1'b1;
        end
        else begin
          valid_stage[s] <= 1'b0;
        end
      end
    end
  endgenerate

  assign sum_out  = stage_reg[NUM_STAGES][0];
  assign valid_out = valid_stage[NUM_STAGES];

endmodule

input.rtl/coeff_ram.sv:
module coeff_ram #(
  parameter NUM_COEFFS  = 32,
  parameter DATA_WIDTH  = 16
)
(
  input  logic                          clk,
  input  logic [$clog2(NUM_COEFFS)-1:0] addr,
  output logic [DATA_WIDTH-1:0]         data_out
);

  // Memory array for coefficients.
  logic [DATA_WIDTH-1:0] mem [0:NUM_COEFFS-1];
  integer i;

  // Synchronous read.
  always_ff @(posedge clk) begin
    data_out <= mem[addr];
  end

endmodule

input.rtl/poly_filter.sv:
module poly_filter #(
  parameter  M           = 4,    // decimation factor
  parameter  TAPS        = 8,    // Taps per phase
  parameter  COEFF_WIDTH = 16,   // Coefficient bit width
  parameter  DATA_WIDTH  = 16,   // Sample data bit width
  localparam ACC_WIDTH   = DATA_WIDTH + COEFF_WIDTH + $clog2(TAPS)
)
(
  input  logic                         clk,
  input  logic                         arst_n,
  input  logic [DATA_WIDTH-1:0]        sample_buffer [0:TAPS-1],
  input  logic                         valid_in,
  // The branch's phase number
  input  logic [$clog2(M)-1:0]         phase,
  output logic [ACC_WIDTH-1:0]         filter_out,
  output logic                         valid
);

  // ---- Stage 0: Register the input sample vector and phase. ----
  logic [DATA_WIDTH-1:0] sample_reg [0:TAPS-1];
  logic [$clog2(M)-1:0]  phase_reg;
  logic                  valid_stage0;
  integer i;
  always_ff @(posedge clk or negedge arst_n) begin
    if (!arst_n) begin
      for (i = 0; i < TAPS; i = i + 1)
        sample_reg[i] <= '0;
      phase_reg    <= '0;
      valid_stage0 <= 1'b0;
    end
    else begin
      if (valid_in) begin
        for (i = 0; i < TAPS; i = i + 1)
          sample_reg[i] <= sample_buffer[i];
        phase_reg    <= phase;
        valid_stage0 <= 1'b1;
      end
      else begin
        valid_stage0 <= 1'b0;
      end
    end
  end

  // ---- Stage 1: Coefficient Fetch ----
  logic [COEFF_WIDTH-1:0] coeff [0:TAPS-1];
  genvar j;
  generate
    for (j = 0; j < TAPS; j = j + 1) begin : coeff_fetch
      logic [$clog2(M*TAPS)-1:0] addr;
      assign addr = phase_reg * TAPS + j;
      coeff_ram #(
        .NUM_COEFFS(M*TAPS),
        .DATA_WIDTH(COEFF_WIDTH)
      ) u_coeff_ram (
        .clk     (clk),
        .addr    (addr),
        .data_out(coeff[j])
      );
    end
  endgenerate

  logic valid_stage1;
  always_ff @(posedge clk or negedge arst_n) begin
    if (!arst_n)
      valid_stage1 <= 1'b0;
    else
      valid_stage1 <= valid_stage0;
  end

  // ---- Stage 2: Multiply the registered samples with coefficients ----
  logic [DATA_WIDTH+COEFF_WIDTH-1:0] products [0:TAPS-1];
  integer k;
  always_comb begin
    for (k = 0; k < TAPS; k = k + 1)
      products[k] = sample_reg[k] * coeff[k];
  end

  // ---- Stage 3: Sum the products using the adder_tree ----
  logic [ACC_WIDTH-1:0] sum_result;
  logic                 valid_adder;
  adder_tree #(
    .NUM_INPUTS(TAPS),
    .DATA_WIDTH(DATA_WIDTH+COEFF_WIDTH)
  ) u_adder_tree_filter (
    .clk      (clk),
    .arst_n   (arst_n),
    .valid_in (valid_stage1),
    .data_in  (products),
    .sum_out  (sum_result),
    .valid_out(valid_adder)
  );

  // ---- Stage 4: Output Registration ----
  always_ff @(posedge clk or negedge arst_n) begin
    if (!arst_n) begin
      filter_out <= '0;
      valid      <= 1'b0;
    end
    else begin
      filter_out <= sum_result;
      valid      <= valid_adder;
    end
  end

endmodule

input.rtl/shift_register.sv:
module shift_register #(
  parameter TAPS  = 32,   // TOTAL_TAPS = N * TAPS
  parameter DATA_WIDTH  = 16
)
(
  input  logic                  clk,
  input  logic                  arst_n,
  input  logic                  load,         // Asserted when a new sample is to be shifted in
  input  logic [DATA_WIDTH-1:0] new_sample,
  output logic [DATA_WIDTH-1:0] data_out [0:TAPS-1],
  output logic                  data_out_val  // Indicates that data_out is updated.
);

  // Internal register array for storing samples.
  logic [DATA_WIDTH-1:0] reg_array [0:TAPS-1];
  integer i;

  always_ff @(posedge clk or negedge arst_n) begin
    if (!arst_n) begin
      for (i = 0; i < TAPS; i = i + 1)
        reg_array[i] <= '0;
      data_out_val <= 1'b0;
    end
    else if (load) begin
      reg_array[0] <= new_sample;
      for (i = TAPS-1; i > 0; i = i - 1)
        reg_array[i] <= reg_array[i-1];
      data_out_val <= 1'b1;
    end
    else begin
      data_out_val <= 1'b0;
    end
  end

  // Continuous assignment of the stored register values to the outputs.
  generate
    for (genvar j = 0; j < TAPS; j = j + 1) begin : assign_output
      assign data_out[j] = reg_array[j];
    end
  endgenerate

endmodule

output.rtl/poly_decimator.sv:
module rtl/poly_decimator #(
  parameter M = 4,
  parameter TAPS = 8,
  parameter COEFF_WIDTH = 16,
  parameter DATA_WIDTH = 16
)
(
  input logic clamp(clk),
  input logic arst_n,
  input logic [DATA_WIDTH-1:0] in_sample,
  input logic valid_in,
  output logic [ACC_WIDTH-1:0] out_sample,
  output logic valid
);

  // State variables
  reg current_stage = 0;
  reg valid_stage = 0;

  // Module instances
  shift_register#(TAPS=32, DATA_WIDTH=16) shift_reg (
    .clk(clamp.clk),
    .arst_n(arst_n),
    .load(!valid_in),
    .new_sample(in_sample),
    .data_out_val(!valid_stage)
  );

  coeff_ram#(
    NUM_COEFFS = 32,
    DATA_WIDTH = 16
  ) coeff_ram (
    .clk(clamp.clk),
    .addr = 0,
    .data_out = 0
  );

  poly_filter#(
    M = 4,
    TAPS = 8,
    COEFF_WIDTH = 16,
    DATA_WIDTH = 16
  ) poly_filter (
    .clk(clamp.clk),
    .arst_n(arst_n),
    .in_sample = in_sample,
    .valid_in = valid_in,
    .out_sample = out_sample,
    .valid_out = valid
  );

  adder_tree#(
    NUM_INPUTS = 8,
    DATA_WIDTH = 32
  ) adder_tree (
    .clk(clamp.clk),
    .arst_n(arst_n),
    .valid_in = valid_stage,
    .data_in = poly_filter.sum_out,
    .sum_out = out_sample,
    .valid_out = valid
  );

  // State machine logic
  initial_state: current_stage = 0;
  always_ff @posedge(clk) begin
    case(current_stage)
    default: current_stage = 0;
    wait #clog2(M * TAPS); // Wait time for full window collection
    endcase

    // Initialization phase
    valid_stage = 0;
    state_reg[0] <= in_sample;
    valid_state0 <= 1'b1;
    valid_stage0 <= 1'b1;
    state_reg[1] <= poly_filter.filter_out;
    valid_stage1 <= 1'b0;

    // Processing phase
    valid_stage = 1;
    state_reg[1] <= poly_filter.filter_out;
    valid_stage0 <= 1'b0;
    valid_stage1 <= 1'b1;
    state_reg[2] <= adder_tree.sum_out;
    valid_stage2 <= 1'b1;

    // Output phase
    valid_stage = 2;
    state_reg[2] <= adder_tree.sum_out;
    valid_stage0 <= 1'b0;
    valid_stage1 <= 1'b0;
    valid_stage2 <= 1'b0;

    // Update output
    out_sample <= adder_tree.sum_out;
    valid <= 1'b0;

    // Cycle back to initialization
    current_stage = 0;
  endcase
  end

input.rtl/prbs_gen_check.sv:
/**************************************************************************
FILENAME:    prbs_gen_check.sv
DESCRIPTION: This module generates or checks a PRBS pattern.
**************************************************************************/

module prbs_gen_check #(
   parameter CHECK_MODE  = 0,              // 0: uses LFSR structure to generate a PRBS pattern, 1: the incoming data is loaded into prbs registers and compared with locally generated PRBS pattern.
   parameter POLY_LENGTH = 31,             // length of the polynomial.(number of shift register stages)
   parameter POLY_TAP    = 3,              // Intermedite stage that is xored with the last stage to generate the next prbs bit.
   parameter WIDTH       = 16              // Bus size of data_in and data_out.
   )(
   input                         clk     , // clock input
   input                         rst     , // synchronous reset, active high
   input         [WIDTH-1:0]     data_in , // input data to be checked(checker mode), tied to 0 (generator mode)
   output logic  [WIDTH-1:0]     data_out  // generated prbs pattern (generator mode), error found (checker mode).
);

logic [1:POLY_LENGTH] prbs [WIDTH:0];
logic [WIDTH-1:0]     prbs_xor_a;
logic [WIDTH-1:0]     prbs_xor_b;
logic [WIDTH:1]       prbs_msb;
logic [1:POLY_LENGTH] prbs_reg = {(POLY_LENGTH){1'b1}};

assign prbs[0]   = prbs_reg;

genvar i;
generate for(i=0; i<WIDTH; i=i+1) begin
   assign prbs_xor_a[i] = prbs[i][POLY_TAP] ^ prbs[i][POLY_LENGTH];
   assign prbs_xor_b[i] = prbs_xor_a[i] ^ data_in[i];
   assign prbs_msb[i+1] = (CHECK_MODE==0) ? prbs_xor_a[i] : data_in[i];
   assign prbs[i+1]     = {prbs_msb[i+1],prbs[i][1:POLY_LENGTH-1]};
end
endgenerate

always_ff @ (posedge clk) begin
   if(rst) begin
      prbs_reg <= {POLY_LENGTH{1'b1}};
      data_out <= {WIDTH{1'b1}};
   end else begin
      prbs_reg <= prbs[WIDTH];
      data_out <= prbs_xor_b;   
   end
end

endmodule

output.rtl/scrambler_descrambler.sv:
Module header
module scrambler_descrambler (
    parameter POLY_LENGTH = 31,
    parameter POLY_TAP = 3,
    parameter WIDTH = 16,
    input     clk,
    input     rst,
    input     bypass_scrambling,
    input     data_in,
    input     valid_in,
    output    data_out,
    output    valid_out,
    output    bit_count
);

// Instantiate the PRBS generator/checker module
parameter CHECK_MODE = 0;
prbs_gen_check prbs_generator (
    .clk(clk),
    .rst(rst),
    .data_in(zero), // Send 0 during generator mode
    .data_out(data_out),
    .CHECK_MODE(CHECK_MODE),
    .POLY_LENGTH(POLY_LENGTH),
    .POLY_TAP(POLY_TAP),
    .WIDTH(WIDTH)
);

// Instantiate the PRBS generator/checker module in checker mode
parameter CHECK_MODE_CHECKER = 1;
prbs_gen_check prbs_checker (
    .clk(clk),
    .rst(rst),
    .data_in(data_in),
    .data_out(data_out),
    .CHECK_MODE(CHECK_MODE_CHECKER),
    .POLY_LENGTH(POLY_LENGTH),
    .POLY_TAP(POLY_TAP),
    .WIDTH(WIDTH)
);

// Bypass scrambling logic
always_ff @ (posedge clk) begin
    if (bypass_scrambling) begin
        data_out <= data_in;
        valid_out <= 1;
    end else begin
        // Scrambling/descrambling logic
        if (rst) begin
            prbs_generatorrst asserted, prbs_checker also asserted?
            prbs_generatorrst prbs_generator.rst prbs_checker.rst;
            data_out <= z;
            valid_out <= 0;
        end else begin
            // Generator mode: send 0 to data_in
            if (CHECK_MODE == 0) {
                prbs_generator.data_in = z;
            } else if (CHECK_MODE == 1) {
                prbs_checker.data_in = data_in;
            }

            // Always update data_out
            data_out <= prbs_generator.data_out;
        end
    end
end

// Counter for bit count
always @* begin
    if (valid_in) begin
        bit_count += WIDTH;
    end
end

// Signal assertions for testing purposes
wire asserts_bit_count(bit_count);
endmodule

input.rtl/fsm.sv:
module fsm (
    input clk,
    input reset,
    input [3:0] input_signal,
    input [63:0] config_state_map_flat,
    input [127:0] config_transition_map_flat,
    output reg [7:0] current_state,
    output reg error_flag,
    output reg [7:0] operation_result
);


    reg [7:0] state;
    reg [7:0] next_state;

    wire [7:0] config_state_map0 = config_state_map_flat[7:0];
    wire [7:0] config_state_map1 = config_state_map_flat[15:8];
    wire [7:0] config_state_map2 = config_state_map_flat[23:16];
    wire [7:0] config_state_map3 = config_state_map_flat[31:24];
    wire [7:0] config_state_map4 = config_state_map_flat[39:32];
    wire [7:0] config_state_map5 = config_state_map_flat[47:40];
    wire [7:0] config_state_map6 = config_state_map_flat[55:48];
    wire [7:0] config_state_map7 = config_state_map_flat[63:56];

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state         <= 0;
            current_state <= 0;
            error_flag    <= 0;
        end else begin
            state         <= next_state;
            current_state <= next_state;
        end
    end

    always @(*) begin
        integer idx;
        idx = (state << 4) + input_signal; 
        next_state = config_transition_map_flat[(idx * 8) + 7 -: 8];

        if (next_state > 8'h7) begin
            error_flag = 1;
            next_state = 0; 
        end else begin
            error_flag = 0;
        end

        case (state)
            8'h0: operation_result = config_state_map0 + input_signal;
            8'h1: operation_result = config_state_map1 - input_signal;
            8'h2: operation_result = config_state_map2 & input_signal;
            8'h3: operation_result = config_state_map3 | input_signal;
            default: operation_result = 8'hFF; 
        endcase
    end

endmodule

