module sorting_engine #(parameter WIDTH = 8)(
    input                     clk,
    input                     rst,
    input                     start,      // Start the sort when start=1
    input  [8*WIDTH-1:0]      in_data,    // 8 inputs, each WIDTH bits
    output reg                done,
    output reg [8*WIDTH-1:0]  out_data    // 8 outputs, sorted ascending
);

  // FSM state encoding
  localparam IDLE      = 3'd0,
             LOAD      = 3'd1,
             SORT_PAIRS= 3'd2,
             MERGE_2_1 = 3'd3,  // Merge first two sorted pairs into a 4-element group
             MERGE_2_2 = 3'd4,  // Merge second two sorted pairs into a 4-element group
             MERGE_4   = 3'd5,  // Merge the two 4-element groups into final 8-element sorted list
             DONE      = 3'd6;

  reg [2:0] state;

  // Internal storage for data at different stages.
  reg [WIDTH-1:0] stage0 [7:0];           // Loaded input data
  reg [WIDTH-1:0] sorted_pairs [7:0];     // After pair compare–swap
  reg [WIDTH-1:0] merge4_right [3:0];      // First 4–element sorted group (from indices 0–3)
  reg [WIDTH-1:0] merge4_left [3:0];     // Second 4–element sorted group (from indices 4–7)
  reg [WIDTH-1:0] final_sorted [7:0];     // Final 8–element sorted result

  // Merge pointers and counter used for sequential merging
  reg [3:0] merge_count;  // Counts how many outputs have been merged in current merge stage
  reg [2:0] ptr1, ptr2;   // Pointers for the two arrays being merged

  integer i; // loop variable for for–loops

  always @(posedge clk or posedge rst) begin
    if (rst) begin
      state      <= IDLE;
      done       <= 0;
      out_data   <= 0;
      merge_count<= 0;
      ptr1       <= 0;
      ptr2       <= 0;
    end else begin
      case (state)
        // Wait for the start signal.
        IDLE: begin
          done <= 0;
          if (start)
            state <= LOAD;
        end

        // Capture the 8 input elements from the flat bus into an array.
        LOAD: begin
          for (i = 0; i < 8; i = i + 1) begin
            stage0[i] <= in_data[i*WIDTH +: WIDTH];
          end
          state <= SORT_PAIRS;
        end

        // Stage 1: Compare-swap each adjacent pair.
        // The 8 numbers are divided into 4 pairs: indices {0,1}, {2,3}, {4,5}, {6,7}.
        SORT_PAIRS: begin
          // Pair 0
          if (stage0[0] <= stage0[1]) begin
            sorted_pairs[0] <= stage0[0];
            sorted_pairs[1] <= stage0[1];
          end else begin
            sorted_pairs[0] <= stage0[1];
            sorted_pairs[1] <= stage0[0];
          end
          // Pair 1
          if (stage0[2] <= stage0[3]) begin
            sorted_pairs[2] <= stage0[2];
            sorted_pairs[3] <= stage0[3];
          end else begin
            sorted_pairs[2] <= stage0[3];
            sorted_pairs[3] <= stage0[2];
          end
          // Pair 2
          if (stage0[4] <= stage0[5]) begin
            sorted_pairs[4] <= stage0[4];
            sorted_pairs[5] <= stage0[5];
          end else begin
            sorted_pairs[4] <= stage0[5];
            sorted_pairs[5] <= stage0[4];
          end
          // Pair 3
          if (stage0[6] <= stage0[7]) begin
            sorted_pairs[6] <= stage0[6];
            sorted_pairs[7] <= stage0[7];
          end else begin
            sorted_pairs[6] <= stage0[7];
            sorted_pairs[7] <= stage0[6];
          end
          // Initialize pointers for first merge stage (MERGE_2_1)
          ptr1        <= 0;
          ptr2        <= 0;
          merge_count <= 0;
          state       <= MERGE_2_1;
        end

        // Stage 2a: Merge the first two sorted pairs (indices 0–1 and 2–3)
        MERGE_2_1: begin
          // Use ptr1 for sorted_pairs[0:1] and ptr2 for sorted_pairs[2:3].
          if ((ptr1 < 2) && (ptr2 < 2)) begin
            if (sorted_pairs[ptr1] <= sorted_pairs[ptr2+2]) begin
              merge4_right[merge_count] <= sorted_pairs[ptr1];
              ptr1 <= ptr1 + 1;
            end else begin
              merge4_right[merge_count] <= sorted_pairs[ptr2+2];
              ptr2 <= ptr2 + 1;
            end
          end else if (ptr1 < 2) begin
            merge4_right[merge_count] <= sorted_pairs[ptr1];
            ptr1 <= ptr1 + 1;
          end else if (ptr2 < 2) begin
            merge4_right[merge_count] <= sorted_pairs[ptr2+2];
            ptr2 <= ptr2 + 1;
          end
          // Check if 4 elements have been merged.
          if (merge_count == 3) begin
            merge_count <= 0;
            ptr1        <= 0;
            ptr2        <= 0;
            state       <= MERGE_2_2;
          end else begin
            merge_count <= merge_count + 1;
          end
        end

        // Stage 2b: Merge the second two sorted pairs (indices 4–5 and 6–7)
        MERGE_2_2: begin
          // Use ptr1 for sorted_pairs[4:5] and ptr2 for sorted_pairs[6:7].
          if ((ptr1 < 2) && (ptr2 < 2)) begin
            if (sorted_pairs[ptr1+4] <= sorted_pairs[ptr2+6]) begin
              merge4_left[merge_count] <= sorted_pairs[ptr1+4];
              ptr1 <= ptr1 + 1;
            end else begin
              merge4_left[merge_count] <= sorted_pairs[ptr2+6];
              ptr2 <= ptr2 + 1;
            end
          end else if (ptr1 < 2) begin
            merge4_left[merge_count] <= sorted_pairs[ptr1+4];
            ptr1 <= ptr1 + 1;
          end else if (ptr2 < 2) begin
            merge4_left[merge_count] <= sorted_pairs[ptr2+6];
            ptr2 <= ptr2 + 1;
          end
          // Check if merge of 4 elements is complete.
          if (merge_count == 3) begin
            merge_count <= 0;
            ptr1        <= 0;
            ptr2        <= 0;
            state       <= MERGE_4;
          end else begin
            merge_count <= merge_count + 1;
          end
        end

        // Stage 3: Merge the two 4–element groups (merge4_right and merge4_left)
        MERGE_4: begin
          if ((ptr1 < 4) && (ptr2 < 4)) begin
            if (merge4_right[ptr1] <= merge4_left[ptr2]) begin
              final_sorted[merge_count] <= merge4_right[ptr1];
              ptr1 <= ptr1 + 1;
            end else begin
              final_sorted[merge_count] <= merge4_left[ptr2];
              ptr2 <= ptr2 + 1;
            end
          end else if (ptr1 < 4) begin
            final_sorted[merge_count] <= merge4_right[ptr1];
            ptr1 <= ptr1 + 1;
          end else if (ptr2 < 4) begin
            final_sorted[merge_count] <= merge4_left[ptr2];
            ptr2 <= ptr2 + 1;
          end
          // Check if all 8 elements have been merged.
          if (merge_count == 7) begin
            merge_count <= 0;
            state       <= DONE;
          end else begin
            merge_count <= merge_count + 1;
          end
        end

        // Final state: pack the final_sorted array back into out_data and assert done.
        DONE: begin
          for (i = 0; i < 8; i = i + 1) begin
            out_data[i*WIDTH +: WIDTH] <= final_sorted[i];
          end
          done  <= 1;
          // Optionally, return to IDLE (or hold in DONE) so a new sort can begin.
          state <= IDLE;
        end

        default: state <= IDLE;
      endcase
    end
  end

endmodule

output.rtl/order_matching_engine.sv:
module order_matching_engine #(parameter PRICE_WIDTH = 16)(
    input     clk,
    input     rst,
    input     start,
    input  [8*PRICE_WIDTH-1:0] bid_orders,
    input  [8*PRICE_WIDTH-1:0] ask_orders,
    output reg   match_valid,
    output reg [PRICE_WIDTH-1:0] matched_price,
    output reg   done,
    output reg   latency_error
);

  localparam IDLE     = 3'd0,
             LOAD     = 3'd1,
             SORT_BIDS = 3'd2,
             SORT_ASKS = 3'd3,
             GET Match = 3'd4,
             POST     = 3'd5,

  reg [2:0] state;

  // Internal storage for bid and ask orders
  reg [WIDTH-1:0] bid_reg [8];
  reg [WIDTH-1:0] ask_reg [8];

  // Variables for extracted orders
  reg [WIDTH-1:0] best_bid, best_ask;

  // Counter for latency measurement
  reg latency_counter = 0;

  always @(posedge clk or posedge rst) begin
    if (rst) begin
      state = IDLE;
      done = 0;
      match_valid = 0;
      best_bid = 0;
      best_ask = 0;
      latency_counter = 0;
    else begin
      case (state)
        IDLE: begin
          done = 0;
          state = LOAD;
          // Load bid orders
          for (int i = 0; i < 8; i = i + 1) begin
            bid_reg[i] <= bid_orders[i * WIDTH +: WIDTH];
          end
          // Load ask orders
          for (int i = 0; i < 8; i = i + 1) begin
            ask_reg[i] <= ask_orders[i * WIDTH +: WIDTH];
          end
          state = SORT_BIDS;
        end

        SORT_BIDS: begin
          // Sort bid orders
          // (Assuming bid_orders is already loaded via the above loop)
          // Using sorting_engine for bid orders
          // Wire bid_orders to sorting_engine's in_data
          reg [8*WIDTH-1:0] sorted_bids;
          assign sorted_bids = bid_reg;
          // Create a temporary register to hold the sorted results
          reg [8*WIDTH-1:0] temp_bids;
          // Copy sorted_bids to temp_bids
          temp_bids = sorted_bids;
          // Sort the bids
          assign temp_bids -> sorting_engine.in_data;
          // Wait for sorting_engine to complete (20 cycles)
          // After 20 cycles, the final_sorted is in sorting_engine.final_sorted
          // Wire the final_sorted to best_bid
          assign best_bid = sorting_engine.final_sorted[7];
          // Set state to SORT_ASKS
          state = SORT_ASKS;
          // Increment latency counter while waiting
          latency_counter <= latency_counter + 1;
        end

        SORT_ASKS: begin
          // Sort ask orders similarly
          // (Assume ask_orders is already loaded via the above loop)
          // Wire ask_orders to sorting_engine's in_data
          reg [8*WIDTH-1:0] sortedAsks;
          assign sortedAsks = ask_reg;
          reg [8*WIDTH-1:0] temp_Ask;
          temp_Ask = sortedAsks;
          assign temp_Ask -> sorting_engine.in_data;
          // Wait for sorting_engine to complete
          // After 20 cycles, the final_sorted is in sorting_engine.final_sorted
          // Wire the final_sorted to best_ask
          assign best_ask = sorting_engine.final_sorted[0];
          // Set state to GET Match
          state = GET Match;
          latency_counter <= latency_counter + 1;
        end

        GET Match: begin
          // Compare best_bid and best_ask
          if (best_bid > best_ask) begin
            // Match found
            match_valid = 1;
            matched_price = best_ask;
          else begin
            match_valid = 0;
            matched_price = 0;
          end
          // Set state to POST
          state = POST;
          // Increment latency counter up to 21
          if (latency_counter < 20) begin
            latency_counter <= latency_counter + 1;
          else begin
            done <= 1;
            match_valid <= 0;
            matched_price <= 0;
            // Ensure total latency is 21 cycles
            if (latency_counter > 20) {
              latency_error <= 1;
            }
          end
        end

        POST: begin
          // All done
          done <= 1;
          // Reset latency counter
          latency_counter <= 0;
        end
      endcase
    end
  end
endmodule

input.rtl/brick_sort.sv:
module brick_sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // ----------------------------------------------------------
    // Internal Parameters and State Encoding
    // ----------------------------------------------------------
    localparam IDLE = 2'd0,
               LOAD = 2'd1,
               SORT = 2'd2,
               DONE = 2'd3;

    // ----------------------------------------------------------
    // Internal Registers
    // ----------------------------------------------------------
    reg [1:0]  state, next_state;

    // Store data in a register array for easy swapping
    reg [WIDTH-1:0] data_array [0:N-1];

    // Pass counter: we will run up to N passes
    reg [$clog2(N+1)-1:0] pass_cnt;

    // Pair index: on each pass, we compare-swap one pair per clock
    reg [$clog2(N/2+1):0] pair_idx;

    // ----------------------------------------------------------
    // Next-State Logic
    // ----------------------------------------------------------
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = LOAD;
            end

            LOAD: begin
                // After loading input data, go to SORT state
                next_state = SORT;
            end

            SORT: begin
                // Once we've completed N passes, sorting is done
                if (pass_cnt == N)
                    next_state = DONE;
            end

            DONE: begin
                // Optionally return to IDLE if desired
                // For a one-shot, we can just stay in DONE unless reset
                // Here, we return to IDLE if start is deasserted
                if (!start)
                    next_state = IDLE;
            end
        endcase
    end

    // ----------------------------------------------------------
    // Sequential State Update
    // ----------------------------------------------------------
    always @(posedge clk or posedge rst) begin
        if (rst)
            state <= IDLE;
        else
            state <= next_state;
    end

    // ----------------------------------------------------------
    // Main Control: pass_cnt, pair_idx, and compare-swap
    // ----------------------------------------------------------
    integer i;
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            done      <= 1'b0;
            pass_cnt  <= 0;
            pair_idx  <= 0;
        end
        else begin
            case (state)

                //--------------------------------------
                // IDLE: wait for start, clear signals
                //--------------------------------------
                IDLE: begin
                    done     <= 1'b0;
                    pass_cnt <= 0;
                    pair_idx <= 0;
                end

                //--------------------------------------
                // LOAD: capture input data into array
                //--------------------------------------
                LOAD: begin
                    // Load all N elements from in_data
                    for (i = 0; i < N; i = i + 1) begin
                        data_array[i] <= in_data[i*WIDTH +: WIDTH];
                    end
                    // Initialize counters
                    pass_cnt <= 0;
                    pair_idx <= 0;
                end

                //--------------------------------------
                // SORT: perform Brick Sort passes
                //--------------------------------------
                SORT: begin
                    // Compare-swap the current pair
                    // Check if we are within the valid pair range
                    // Distinguish odd-even pass from even-odd pass
                    if (pass_cnt[0] == 1'b0) begin
                        // even-odd pass => pair = (2*pair_idx, 2*pair_idx+1)
                        for(pair_idx=0; pair_idx<(N+1)/2; pair_idx=pair_idx+1) begin
                            if (data_array[2*pair_idx] > data_array[2*pair_idx+1]) begin
                                // Swap
                                {data_array[2*pair_idx], data_array[2*pair_idx+1]} <= {data_array[2*pair_idx+1], data_array[2*pair_idx]};
                            end
                        end
                    end
                    else begin
                        // odd-even pass => pair = (2*pair_idx+1, 2*pair_idx+2
                        for(pair_idx=0; pair_idx<((N+1)/2) - 1; pair_idx=pair_idx+1) begin
                            if ((2*pair_idx+2) < N) begin
                                if (data_array[2*pair_idx+1] > data_array[2*pair_idx+2]) begin
                                    // Swap
                                    {data_array[2*pair_idx+1], data_array[2*pair_idx+2]} <= {data_array[2*pair_idx+2], data_array[2*pair_idx+1]};
                                end
                            end
                        end
                    end

                    // Completed all pairs in this pass -> next pass
                    pass_cnt <= pass_cnt + 1;

                end // SORT

                //--------------------------------------
                // DONE: output final data, assert done
                //--------------------------------------
                DONE: begin
                    done <= 1'b1;
                    // Drive out_data from data_array
                    for (i = 0; i < N; i = i + 1) begin
                        out_data[i*WIDTH +: WIDTH] <= data_array[i];
                    end
                end

            endcase
        end
    end

endmodule

input.rtl/bubble_sort.sv:
module bubble_sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal registers to hold the array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0]  state, next_state;

    // Variables for bubble sort indexing
    reg [$clog2(N)-1:0] i;  // Outer loop index
    reg [$clog2(N)-1:0] j;  // Inner loop index

    // Wires for comparison and swap
    wire [WIDTH-1:0] val_j;
    wire [WIDTH-1:0] val_j1;

    assign val_j  = array[j];
    assign val_j1 = array[j+1];

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Transition to DONE once all passes are complete
                if (i == (N-1) && j == (N-2))
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // FSM: Output and counter updates
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            i <= 0;
            j <= 0;
            done <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        // Load the array from in_data
                        for (int k = 0; k < N; k = k + 1) begin
